Here are pytest‑style unit tests that cover happy paths, edge cases, and error cases.

```python
import pytest
from your_module import slugify

def test_slugify_happy_basic():
    assert slugify("Hello World") == "hello-world"

def test_slugify_happy_with_punctuation():
    assert slugify("Hello, World!!!") == "hello-world"

def test_slugify_happy_with_underscores():
    assert slugify("hello_world_test") == "hello-world-test"

def test_slugify_happy_with_mixed_spaces():
    assert slugify("  Hello   World  ") == "hello-world"

def test_slugify_happy_collapse_multiple_hyphens():
    assert slugify("Hello---World") == "hello-world"

def test_slugify_removes_leading_and_trailing_hyphens():
    assert slugify("---Hello World---") == "hello-world"

def test_slugify_non_ascii_word_characters_kept():
    # \w includes some unicode word characters
    assert slugify("café déjà vu") == "café-déjà-vu"

def test_slugify_numbers_and_words():
    assert slugify("Version 2.0 Release") == "version-20-release"

# Edge cases
def test_slugify_empty_string():
    assert slugify("") == ""

def test_slugify_only_spaces():
    assert slugify("     ") == ""

def test_slugify_only_punctuation():
    assert slugify("!!!???") == ""

def test_slugify_only_hyphens():
    assert slugify("---") == ""

def test_slugify_mixed_symbols_removed():
    assert slugify("@hello #world$") == "hello-world"

# Error cases
def test_slugify_non_string_input():
    with pytest.raises(AttributeError):
        slugify(None)

def test_slugify_int_input():
    with pytest.raises(AttributeError):
        slugify(123)
